Here are the public test cases for feature10_1_encode_objects:
{
  "description": "Encode a structured object to a block mapping; nested objects are indented by the configured indentation size, and embedded lists and maps are nested under their key.",
  "cases": [
    {
      "input": {
        "op": "encode",
        "shape": "named",
        "value": {
          "name": "The name"
        }
      },
      "expected_output": "name: \"The name\""
    },
    {
      "input": {
        "op": "encode",
        "shape": "people",
        "value": {
          "firstPerson": {
            "name": "name1"
          },
          "secondPerson": {
            "name": "name2"
          }
        }
      },
      "expected_output": "firstPerson:\n  name: \"name1\"\nsecondPerson:\n  name: \"name2\""
    }
  ]
}

