}

Here are the public test cases for feature12_parse_to_node:
{
  "description": "Parse a document into a generic node tree without a target type, exposing the structural shape (scalars, sequences, mappings, nulls and tagged nodes) and scalar contents.",
  "cases": [
    {
      "input": {
        "op": "parse",
        "document": "123"
      },
      "expected_output": "scalar '123'"
    },
    {
      "input": {
        "op": "parse",
        "document": "foo: bar\nbaz: 3"
      },
      "expected_output": "map (size: 2)\nkey 'foo'\n  scalar 'bar'\nkey 'baz'\n  scalar '3'"
    },
    {
      "input": {
        "op": "parse",
        "document": "text: OK\nnode: !testtag 2024-01-01"
      },
      "expected_output": "map (size: 2)\nkey 'text'\n  scalar 'OK'\nkey 'node'\n  tagged !!testtag\n    scalar '2024-01-01'"
    }
  ]
}

